sys_script_include.script:
/**
 * GEM/Nguyenlh - 15.05.2026:
 * TAM/Sprint 3/Story TAM_46
 * Queries the Recruitment Request table and returns the Position field data.
 * @param sysparm_recruit_id: The sys_id of the Recruitment Request record 
 * @returns {string} JSON string containing the position details
 */

var TAMRecruitmentRequestInfoAJAX = Class.create();
TAMRecruitmentRequestInfoAJAX.prototype = Object.extendsObject(global.AbstractAjaxProcessor, {

    type: 'TAMRecruitmentRequestInfoAJAX',
	getRecruitmentRequestInfo: function() {
		var recruitId = this.getParameter('sysparm_recruit_id');

		var grRecruitmentRequest = new GlideRecord('x_1763182_talent_0_recruitment_request');  
		var result = {};

		if(grRecruitmentRequest.get(recruitId)){
			result = {
				position: grRecruitmentRequest.getDisplayValue('u_position'),
			};
		}
		return JSON.stringify(result);
	},
});
